import{_ as a,o as i,c as o,aw as t}from"./chunks/framework.DLufY-ao.js";const f=JSON.parse('{"title":"Информация","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/frameworks/vue/directives/info.md","filePath":"wiki/dev-commit/frameworks/vue/directives/info.md"}'),r={name:"wiki/dev-commit/frameworks/vue/directives/info.md"};function c(l,e,d,s,n,u){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="информация" tabindex="-1">Информация <a class="header-anchor" href="#информация" aria-label="Permalink to &quot;Информация&quot;">​</a></h1><h2 id="синтаксис-шаблонов" tabindex="-1">Синтаксис шаблонов <a class="header-anchor" href="#синтаксис-шаблонов" aria-label="Permalink to &quot;Синтаксис шаблонов&quot;">​</a></h2><ul><li>Для связывания DOM с данными экземпляра Vue использует синтаксис, основанный на HTML. Все шаблоны Vue являются валидным HTML-кодом, который могут распарсить все HTML-парсеры и браузеры.</li><li>Для работы Vue компилирует шаблоны в <em>render-функции</em> виртуального DOM. В сочетании с системой реактивности, Vue умеет определять минимальное число компонентов для повторной отрисовки и применяет минимальное количество манипуляций к DOM при изменении состояния приложения.</li></ul><h2 id="директивы" tabindex="-1">Директивы <a class="header-anchor" href="#директивы" aria-label="Permalink to &quot;Директивы&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Директивы</p><ul><li><strong>Директивы</strong> - специальные атрибуты с префиксом <code>v-</code>. В качестве значения они принимают одно выражение JavaScript (за исключением <code>v-for</code>). Директива реактивно применяет к DOM изменения при обновлении значения этого выражения</li><li>Некоторые директивы могут принимать «аргумент», разделённый от названия директивы двоеточием <code>v-bind:href=&quot;url&quot;</code>. В данном случае href - аргумент, указывающий директиве <code>v-bind</code> связать атрибут href элемента со значением выражения url</li></ul></div>',5)])])}const _=a(r,[["render",c]]);export{f as __pageData,_ as default};
